import React from 'react';
// import logo from './logo.svg';
import './App.css';
import LogIn from './components/LogIn';
import Dashboard from './components/Dashboard';
import User from './components/User';
// in index.js
import packageJson from '../package.json';

import {
  Container,
  // Row, Col, Button
} from 'react-bootstrap';

import { DataContext } from './data-context.js';
const util = require('./util.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class App extends React.Component {

  static contextType = DataContext;

  constructor(...args) {
    super(...args);

    // let demoUser = {
    //   _id: "5da1387fe58eb52ac31e0ee2",
    //   code: "3299029",
    //   address: "700/309 หมู่ 6 ต.ดอนหัวฬ่อ อ. เมื่อง จ.ชลบุรี",
    //   division: "MT",
    //   email: "",
    //   name: "วิไล แก้วไกรเพชร์",
    //   note: "",
    //   tel1: "172",
    //   tel2: "086-1509040",
    //   unit: "ME",
    //   isAdmin: true
    // };

    // let defaultTab = demoUser.isAdmin ? '#action/1.1' : '#home';

    // // defaultTab = '#stock/out';  //DEV

    if (process.env.NODE_ENV === 'production') {
      this.state = {
        jobs: [], // TODO load in componentWillMount
        users: [],
        machines: [],
        lines: [],
        mainUser: null,
        mainLine: null,
        isAdmin: false,
        loadingState: 0, // 100 (4) = machines, 010 (2) = users, 001 (1) = lines, 111 (7) = All
        // tab: defaultTab,
        // user: demoUser, // DEV
        // user: null,  // PROD
      }
    } else {
      this.state = {
        jobs: [], // TODO load in componentWillMount
        users: [],
        machines: [],
        lines: [],
        // isAdmin: false,
        // mainLine: {
        //   code: '4',
        //   name: 'ACT',
        // },

        isAdmin: true,
        mainUser: null,
        mainLine: {
          code: '__ADMIN__',
          name: '__ADMIN__'
        },

        // mainLine: null,
        loadingState: 0, // 100 (4) = machines, 010 (2) = users, 001 (1) = lines, 111 (7) = All
        // tab: defaultTab,
        // user: demoUser, // DEV
        // user: null,  // PROD
      }
    }

    console.log('App Version:', packageJson.version);
    console.log("React Version:", React.version);
    console.log('process.env.NODE_ENV', process.env.NODE_ENV)
    console.log("API EndPoint:", apiUrl);
    console.log("Refresh Interval:", process.env.REACT_APP_REFRESH_INTERVAL);
    

    // console.log("Demo User", this.state.user);
  }

  UNSAFE_componentWillMount() {
    let data = this.context.data;
    console.log('JobForm.UNSAFE_componentWillMount')

    util.fetchMachines().then(res => {
      let machines = res.data;
      machines.forEach(machine => {
        // console.log(machine)
        if (machine.line !== null)
        machine.lineName = machine.line.name;
      })
      this.setState({
        machines: machines,
        loadingState: this.state.loadingState | 4
      })
    })

    util.fetchRpUsers().then(res => {
      let users = res.data;
      // console.log('App load users',users)
      this.setState({
        users: users,
        loadingState: this.state.loadingState | 2
      })
    })

    util.fetchLines().then(res => {
      let lines = res.data;
      this.setState({
        lines: lines,
        loadingState: this.state.loadingState | 1
      });
    })

  }


  handleLoginSuccess = (user) => {
    console.log('handleLoginSuccess')
    this.context.mainUser = user
    this.setState({
      mainUser: user,
      mainLine: {
        _id: '__ADMIN__',
        code: '__ADMIN__',
        name: '__ADMIN__'
      },
      isAdmin: true,
    })
  }

  handleLoginFailure = () => {
    console.log('handleLoginFailure')
    alert('รหัสผู้ใช้งาน หรือ รหัสผ่าน ไม่ถูกต้อง')
  }

  handleLineSelected = (line) => {
    this.context.mainLine = line
    this.setState({
      mainLine: {
        _id: line._id,
        code: line.code,
        name: line.name
      },
      isAdmin: false,
    })
  }

  handleLogOut = () => {
    this.context.mainLine = null;
    this.setState({
      mainLine: null,
      isAdmin: false
    })
  }
  render() {
    console.log('this.state.loadingState', this.state.loadingState)

    let loading = !(this.state.loadingState === 7);
    return (
      <>
        <DataContext.Provider value={this.state}>
          <Container fluid>
            {this.state.mainLine &&
              <Dashboard
                mainLine={this.state.mainLine}
                isAdmin={this.state.isAdmin}
                onLogOut={this.handleLogOut}
                loading={loading} />
            }

            {!this.state.mainLine &&
              <LogIn
                onLineSelected={this.handleLineSelected}
                onLoginSuccess={this.handleLoginSuccess}
                onLoginFailure={this.handleLoginFailure} />
            }
          </Container>
        </DataContext.Provider>

      </>
    );
  }
}
