import React from 'react';
import '../App.css';
import {
  // Container, Row, 
  Row, Col,
  Button,
  Form,
  DropdownButton, Dropdown,
  ButtonGroup,
  Modal,
} from 'react-bootstrap';

// import "react-select/dist/react-select.css";
import CodeLoginForm from "./CodeLoginForm";
import createFilterOptions from "react-select-fast-filter-options";
import Select from "react-select"; // https://github.com/JedWatson/react-select
import moment from 'moment'; // https://momentjs.com/
import { DataContext } from '../data-context';


const util = require('../util.js');


export class JobForm extends React.Component {

  static contextType = DataContext;
  job = {};
  // lines = [];
  // users = [];
  // machines = [];
  lineMap = {};
  userMap = {};
  machineMap = {};
  workTypeOptions = [];
  equipmentTypeOptions = [];
  viewJob = false;
  editJob = false;
  newJob = false;
  // createGeneralJob = false;
  isSubmitting = false;

  workTypeOptions = [
    { value: 'REPAIR', label: 'REPAIR' },
    { value: 'MODIFY', label: 'MODIFY' },
    { value: 'CHECK', label: 'CHECK' },
    { value: 'INSTALLATION', label: 'INSTALLATION' },
    { value: 'INSPECTION', label: 'INSPECTION' },
    { value: 'OTHER', label: 'OTHER' },
  ];

  

  equipmentTypeOptions = [
    { value: 'ELECTRICAL', label: 'ELECTRICAL' },
    { value: 'MECHANICAL', label: 'MECHANICAL' },
    { value: 'JIG', label: 'JIG' },
    { value: 'HYDRAULIC', label: 'HYDRAULIC' },
    { value: 'PNEUMATIC', label: 'PNEUMATIC' },
    { value: 'OTHER', label: 'OTHER' },
  ];

  jobTemplate = {
    main_type: 0,
    request_time: new Date(),

    code: '',
    // code_4M: this.code4MOptions[0].value,
    request_user_code: '',
    request_user_name: '',
    request_dept_name: '',

    line: null,
    line_code: 0,
    line_name: '',

    machine: '',
    machine_name: '',
    machine_code: '',

    request_cause: '',
    request_comment: '',
    request_work_type: this.workTypeOptions[0].value,
    request_work_type_other: '',
    request_equipment_type: this.equipmentTypeOptions[0].value,
    request_equipment_type_other: "",

    repair_user_code: "",
    repair_user_name: "",
    repair_time: null,

    finish_user_code: "",
    finish_user_name: "",
    finish_time: null,
    finish_cause: "",
    finish_detail: "",
    finish_comment: "",
    finish_work_type: "",
    finish_work_type_other: '',
    finish_protect: "",
    finish_protect_detail: "",
    complete_time: "",
    // sparepart_01_code: "",
    // sparepart_01_name: "",
    // sparepart_01_qty: 0,
    // sparepart_02_code: "",
    // sparepart_02_name: "",
    // sparepart_02_qty: 0,
    // sparepart_03_code: "",
    // sparepart_03_name: "",
    // sparepart_03_qty: 0,
    // sparepart_04_code: "",
    // sparepart_04_name: "",
    // sparepart_04_qty: 0,
    // sparepart_05_code: "",
    // sparepart_05_name: "",
    // sparepart_05_qty: 0,
    // code4M: this.code4MOptions[0],
    workType: this.workTypeOptions[0],
    equipmentType: this.equipmentTypeOptions[0],
    state: 0,
  }

  constructor(...args) {
    super(...args);
    // console.log(this.context);
    // console.log(this.props);
    // TODO no this doesn't work this way.
    this.job = this.jobTemplate;

    // console.log('this.context',this.context)
    // console.log('this.context.lines',this.context.lines)



    let users = []
    this.context.users.forEach((v, i) => {
      this.userMap[v.code] = v;
      let option = { value: v.code, label: v.name }
      users.push(option)
    })

    let lineOptions = []
    this.context.lines.forEach((v, i) => {
      this.lineMap[v._id] = v;
      let option = { value: v._id, label: v.name }
      lineOptions.push(option)
    })

    let machines = []
    this.context.machines.forEach((v, i) => {
      this.machineMap[v._id] = v;
    })

    if (this.context.machines)
      machines = this.prepareMachineOptions();

    // this.context.machines.forEach((v, i) => {
    //   this.machineMap[v.code] = v;
    //   machines.push({ value: v.code, label: `[${v.line}] ${v.name}` })
    // })



    this.state = {
      // ...this.context,
      ...this.job,
      showCodeLoginForm: false,

      users: users,
      lines: lineOptions,
      machines: machines,

    };

    this.handleUserVerificationSuccess = this.handleUserVerificationSuccess.bind(this);
    this.handleUserVerificationFailure = this.handleUserVerificationFailure.bind(this);

  }

  prepareMachineOptions(lineId = null) {
    let machines = []
    console.log('prepareMachineOptions', lineId)
    this.context.machines.forEach((v, i) => {
      // console.log(v.line, line)
      if (lineId === null || v.line._id === lineId) {
        machines.push({ value: v._id, label: `[${v.code}] ${v.name}` })
      }
    })
    return machines
  }

  UNSAFE_componentWillMount() {
    console.log('JobForm.UNSAFE_componentWillMount')

    var job = {};

    // Observe the render mode
    job.request_work_type = job.request_work_type ? job.request_work_type.trim() : '';
    job.request_equipment_type = job.request_equipment_type ? job.request_equipment_type.trim() : '';
    this.newJob = this.props.createMachineJob ? this.props.createMachineJob : false;

    if (this.newJob) {
      job = this.jobTemplate;

    } else if (this.props.data) {
      job = this.props.data;

      let selectedUser = {
        value: job.request_user_code,
        label: job.request_user_name
      }

      let selectedLine = {
        value: job.line_code,
        label: job.line_name
      }
      let selectedMachine = {
        value: job.machine_code,
        label: job.machine_name
      }
      let selectedWorkType = {
        value: job.request_work_type,
        label: job.request_work_type
      }
      let selectedEquipmentType = {
        value: job.request_equipment_type,
        label: job.request_equipment_type
      }
      // Transform users, machines, lines to favour Select component



      // Prep selected users, lines, machines
      // console.log("Selected Options", selectedUser, selectedLine, selectedMachine)

      this.setState({
        selected_request_user: selectedUser,
        selected_line: selectedLine,
        selected_machine: selectedMachine,
        selected_workType: selectedWorkType,
        selected_equipmentType: selectedEquipmentType,
        ...job
        // users: users,
        // lines: lines,
        // machines: machines,
      });
    }


    // console.log('job-------------', job)

  }

  ___UNSAFE_componentWillMount() {
    console.log('JobForm.UNSAFE_componentWillMount')

    util.fetchMachines().then(res => {
      let machines = []
      res.data.forEach((v, i) => {
        this.machineMap[v.code] = v;
        machines.push({ value: v.code, label: `[${v.line}] ${v.name}` })
      })

      util.fetchRpUsers().then(res => {
        let users = []
        res.data.forEach((v, i) => {
          this.userMap[v.code] = v;
          users.push({ value: v.code, label: v.name })
        })
        console.log('userMap', this.userMap)

        util.fetchLines().then(res => {
          // let lines = res.data;
          let lines = []
          // console.log('lines', res.data);
          res.data.forEach((v, i) => {
            this.lineMap[v.code] = v;
            lines.push({ value: v.code, label: v.name })
          })


          this.setState({
            machines: machines,
            users: users,
            lines: lines,
          });
        })
      })
    })
  }

  // handleClose = (e) => {
  //   this.props.handleClose();
  // }

  handleChange = (e) => {
    console.log([e.target.id], e.target.value, e.target.checked, e.target.type)
    if (e.target.type === 'checkbox') {
      this.setState({ [e.target.id]: e.target.checked })
    } else {
      this.setState({ [e.target.id]: e.target.value })
    }
  }

  handleSelectUser = (selectedOption) => {
    // if (this.viewJob) return;
    let key = selectedOption.value;
    this.setState({
      selected_request_user: selectedOption,
      request_user_code: key,
      request_user_name: this.userMap[key].name
    })
  }

  handleSelectMachine = (selectedOption) => {
    // if (this.viewJob) return;
    let key = selectedOption.value;
    console.log("handleMachineSelect", key)
    this.setState({
      selected_machine: selectedOption,
      machine_code: key,
      machine_name: this.machineMap[key].name
    })
  }


  handleSelectLine = (selectedOption) => {
    // if (this.viewJob) return;
    let lineId = selectedOption.value
    let lineName = this.lineMap[lineId].name
    let machines = this.prepareMachineOptions(lineId);

    this.setState({
      selected_line: selectedOption,
      line: lineId,
      line_code: lineId,
      line_name: lineName,
      machines: machines
    });
  }

  handleSelectWorkType = (selectedOption) => {
    // if (this.viewJob) return;
    this.setState({
      selected_workType: selectedOption,
      request_work_type: selectedOption.value,
    })
  }

  handleSelectEquipmentType = (selectedOption) => {
    // if (this.viewJob) return;
    this.setState({
      selected_equipmentType: selectedOption,
      request_equipment_type: selectedOption.value,
    })
  }


  otherValidation = () => {

  }

  prepareJobObject = (job) => {
    // Remove extranous data
    delete job.vendors
    // delete job.isSubmitting
    delete job.users
    delete job.lines
    delete job.machines
    delete job.request_user
    delete job.machine
    // delete job.workType
    // delete job.equipmentType
    delete job.createMachineJob
    return job
  }

  handleSubmit = (event) => {
    // console.log(this.state);
    const form = event.currentTarget;
    event.preventDefault();
    if (form.checkValidity() === false || this.otherValidation()) {
      event.stopPropagation();
      return;
    }


    let job = this.prepareJobObject(this.state);

    console.log("Prepared Job",job);

    switch (job.state) {
      case -1:
        job.state = 0;
        util.saveJob(job)
          .then(res => {
            console.log('Success:', res);
            this.props.handleClose(true);
          })
          .catch(error => {
            this.props.handleClose(false);
            console.error('Error:', error);
          });
        break;
      case 1:
      case 2:
      // // DON'T ALLOW EDIT
      // console.error('Assert error! Edit not allow')
      // console.log("Update job", job)
      // util.updateJob(job)
      //   .then(jsonData => {
      //     console.log('Success:', JSON.stringify(jsonData));
      //     this.props.handleClose(true);
      //   })
      //   .catch(error => {
      //     this.props.handleClose(false);
      //     console.error('Error:', error);
      //   });
      // break;
      case 3:
        // THIS SHOULD NOT HAPPEN
        break;
    }
  }

  openCodeLoginForm = () => this.setState({ showCodeLoginForm: true })
  closeCodeLoginForm = () => this.setState({ showCodeLoginForm: false })


  handleUserVerificationSuccess(user) {
    if (this.state.state === 0) {
      alert(user.name + ' รับงานนี้แล้ว')
      let _this = this;
      this.closeCodeLoginForm()
      let job = this.prepareJobObject(this.state);
      job.repair_time = new Date();
      job.repair_user_code = user.code;
      job.repair_user_name = user.name;
      job.state = 1;
      this.isSubmitting = true;
      util.updateJob(job)
        .then(res => {
          _this.props.handleClose(true);
          this.isSubmitting = false;
        })
    } else if (this.state.state === 1) {
      alert(user.name + ' ปิดงานนี้แล้ว')
      let _this = this;
      this.closeCodeLoginForm()
      let job = this.prepareJobObject(this.state);
      job.finish_time = new Date();
      job.finish_user_code = user.code;
      job.finish_user_name = user.name;
      job.state = 2;
      this.isSubmitting = true;
      util.updateJob(job)
        .then(res => {
          _this.props.handleClose(true);
          this.isSubmitting = false;
        })

    } else {
      console.error("ASSERTATION ERROR invalid job state", this.state.state)
    }
  }

  handleUserVerificationFailure() {
    alert('รหัสทีม หรือ รหัสผู้ใช้ไม่ถูกต้อง')
    this.closeCodeLoginForm()
  }


  render() {
    // this.createMachineJob = this.props.createMachineJob ? this.props.createMachineJob : false

    // let data = this.context.data;
    // let job = this.state;
    // this.viewJob = this.props.readOnly ? this.props.readOnly : false
    let nobutton = this.props.nobutton ? this.props.nobutton : false

    let job = this.state;

    switch (job.state) {
      case -1:
        this.newJob = true
        this.editJob = false
        this.viewJob = false
        break;
      case 0:
      case 1:
        this.newJob = false
        this.editJob = false
        this.viewJob = true
        break;
      case 2:
      case 3:
        this.newJob = false
        this.editJob = false
        this.viewJob = true
        break;
    }

    console.log('viewJob', this.viewJob)
    console.log('render: job', job);

    // this.createGeneralJob = this.props.createGeneralJob ? this.props.createGeneralJob : false


    const machineFilterOptions = createFilterOptions({
      options: this.state.machines
    });

    const lineFilterOptions = createFilterOptions({
      options: this.state.lines
    });

    const userFilterOptions = createFilterOptions({
      options: this.state.users
    });


    return (
      <>
        <Form onSubmit={this.handleSubmit} disabled={this.viewJob}>
          เวลาแจ้งซ่อม: {moment(job.request_time).format('ddd DD MMM YYYY (HH:mm)')}

          <Form.Row>

            <Form.Group as={Col} controlId="request_user_code">
              <Form.Label>ผู้แจ้ง</Form.Label>
              {/* <Form.Control
                  type="text"
                  placeholder="ผู้แจ้ง"
                  value={job.requester_code}
                  onChange={this.handleChange} /> */}

              {this.viewJob &&
                <Form.Control
                  type="text"
                  readOnly
                  defaultValue={this.state.request_user_name} />}

              {!this.viewJob &&
                <Select
                  value={this.state.selected_request_user}
                  filterOptions={userFilterOptions}
                  options={this.state.users}
                  onChange={this.handleSelectUser} />
              }
              {/* <Dropdown onSelect={this.handleUserSelect}>
              <Dropdown.Toggle variant="outline-dark">
                {job.request_user_name}
              </Dropdown.Toggle>
              <Dropdown.Menu>
                {userList}
              </Dropdown.Menu>
            </Dropdown> */}


            </Form.Group>

            <Form.Group as={Col} controlId="line">
              <Form.Label>Line</Form.Label>

              {this.viewJob &&
                <Form.Control
                  type="text"
                  readOnly
                  defaultValue={this.state.line_name} />}

              {!this.viewJob &&
                <Select
                  value={this.state.selected_line}
                  filterOptions={lineFilterOptions}
                  options={this.state.lines}
                  onChange={this.handleSelectLine} />
              }
              {/* <Dropdown onSelect={this.handleLineSelect}>
              <Dropdown.Toggle variant="outline-dark">
                {job.line_name}
              </Dropdown.Toggle>
              <Dropdown.Menu>
                {lineList}
              </Dropdown.Menu>
            </Dropdown>
            */}
            </Form.Group>
          </Form.Row>

          <Form.Row>
            <Form.Group as={Col} controlId="machine">
              <Form.Label>ชื่อเครื่องจักร</Form.Label>
              {this.viewJob &&
                <Form.Control
                  type="text"
                  readOnly
                  defaultValue={this.state.machine_name} />}

              {!this.viewJob &&
                <Select
                  value={this.state.selected_machine}
                  filterOptions={machineFilterOptions}
                  options={this.state.machines}
                  onChange={this.handleSelectMachine} />
              }
            </Form.Group>

          </Form.Row>

          <Form.Row>
            <Form.Group controlId="request_cause">
              <Form.Label>อาการ / สาเหตุที่พบ</Form.Label>
              {this.viewJob &&
                <Form.Control
                  readOnly
                  // type="text"
                  as="textarea"
                  rows="3" cols="80"
                  defaultValue={job.request_cause} />
              }

              {!this.viewJob &&
                <Form.Control
                  // type="text"
                  as="textarea"
                  rows="3" cols="80"
                  value={job.request_cause}
                  onChange={this.handleChange} />
              }
            </Form.Group>
          </Form.Row>

          <Form.Row>
            <Form.Group controlId="request_comment">
              <Form.Label>หมายเหตุ</Form.Label>
              {this.viewJob &&
                <Form.Control
                  readOnly
                  // type="text"
                  as="textarea"
                  rows="2" cols="80"
                  defaultValue={job.request_comment}
                />}

              {!this.viewJob &&
                <Form.Control
                  // type="text"
                  as="textarea"
                  rows="2" cols="80"
                  value={job.request_comment}
                  onChange={this.handleChange} />
              }
            </Form.Group>
          </Form.Row>

          <Form.Row>
            <Form.Group as={Col}>
              <Form.Label>ประเภทของงาน</Form.Label>
              {this.viewJob &&
                <Form.Control
                  type="text"
                  readOnly
                  defaultValue={this.state.request_work_type} />}

              {!this.viewJob &&
                <Select
                  value={this.state.selected_workType}
                  // filterOptions={userFilterOptions}
                  options={this.workTypeOptions}
                  onChange={this.handleSelectWorkType} />
              }

              {this.state.workType.value === 'OTHER' &&
                <span>ระบุรายละเอียด: <Form.Control
                  id="request_work_type_other"
                  type="text"
                  readOnly={this.viewJob}
                  placeholder="Other"
                  value={job.request_work_type_other}
                  onChange={this.handleChange} />
                </span>
              }
              {this.state.state === 2 &&
                <Form.Label>ประเภทของอุปกรณ์</Form.Label>
              }
              {/* {this.state.state == 2 &&
                <Form.Control
                  type="text"
                  readOnly
                  defaultValue={this.state.request_equipment_type} />} */}

              {this.state.state === 2 &&
                <Select
                  value={this.state.selected_equipmentType}
                  // filterOptions={userFilterOptions}
                  options={this.equipmentTypeOptions}
                  onChange={this.handleSelectEquipmentType} />
              }
              {this.state.state === 2 && this.state.equipmentType.value === 'OTHER' &&
                <span>ระบุรายละเอียด: <Form.Control
                  id="finish_work_type_other"
                  type="text"
                  // readOnly={this.viewJob}
                  placeholder="ระบุรายละเอียด"
                  value={job.finish_work_type_other}
                  onChange={this.handleChange} />
                </span>
              }

              {/* {this.state.state === 2 &&
                <>
                  <Form.Label>Code</Form.Label>
                  <Form.Control
                    id="code"
                    type="text"
                    placeholder="Code"
                    value={job.code}
                    onChange={this.handleChange} />
                </>
              } */}

            </Form.Group>
          </Form.Row>
          {(this.state.state === 1) &&
            <Form.Row>
              <Col>
                <Form.Group controlId="repair_user_name">
                  <Form.Label>ผู้ซ่อม</Form.Label>
                  <Form.Control
                    readOnly
                    style={{ width: '100%' }}
                    type="text"
                    defaultValue={job.repair_user_name}
                  />
                </Form.Group>
              </Col>
            </Form.Row>
          }
          <Form.Row>
            {!nobutton && !this.viewJob && !this.isSubmitting && <Button block variant="success" onClick={this.handleSubmit} disabled={this.isSubmitting}>บันทึก</Button>}
            {!nobutton && job.state === 0 && !this.isSubmitting && <Button block variant="danger" onClick={this.openCodeLoginForm} disabled={this.isSubmitting}>รับงาน</Button>}
            {!nobutton && job.state === 1 && !this.isSubmitting && <Button block variant="warning" onClick={this.openCodeLoginForm} disabled={this.isSubmitting}>ปิดงาน</Button>}
            {!nobutton && !this.isSubmitting && <Button block variant="secondary" onClick={() => this.props.handleClose(false)}>ปิดหน้านี้</Button>}
          </Form.Row>
        </Form>

        <Modal
          show={this.state.showCodeLoginForm}
          onHide={this.closeCodeLoginForm}
          size="sm"
          aria-labelledby="contained-modal-title-vcenter"
          style={{ backgroundColor: '#000022' }}
          keyboard>
          <Modal.Header closeButton>
            <Modal.Title>ป้อนรหัสประจำตัว</Modal.Title>
          </Modal.Header>
          <Modal.Body>
            <CodeLoginForm
              handleUserVerificationSuccess={this.handleUserVerificationSuccess}
              handleUserVerificationFailure={this.handleUserVerificationFailure}
            />
          </Modal.Body>
          {/* <Modal.Footer>
          </Modal.Footer> */}
        </Modal >
      </>
    );
  }
}
