import React from 'react';
import '../App.css';
import {
  Container, Table, Row, Col,
  Button
} from 'react-bootstrap';

import { DataContext } from '../data-context.js';
import moment from 'moment'; // https://momentjs.com/
import { ContextMenu, MenuItem, ContextMenuTrigger } from "react-contextmenu";
// import { util } from 'node-forge';
const util = require('../util.js');
export default class JobTable extends React.Component {

  static contextType = DataContext;
  color = '#ffffff';

  constructor(...args) {
    super(...args);
    // console.log(this.context);
    this.state = {
      ...this.context
    };

    if (this.props.backlog) this.color = '#ffaaaa';
    if (this.props.wip) this.color = '#aaaaff';
    if (this.props.done) this.color = '#aaffaa';
  }

  render() {
    let jobList = [];
    let data = this.props.data;
    // let data = this.context.data;
    // console.log("data",typeof(data),data);

    // data.map((v, i) => {
    jobList = data.map((v, i) => {
      // console.log('v',v.request_time)
      return (
        <Row key={i} style={{ color: this.color }} onContextMenu={(e) => console.log(e)} onClick={(e) => this.props.handleJobClick(e, v)}>
          <Table striped bordered style={{ color: this.color }}>
            <tbody>
              <tr>
                <td>
                  {util.getDurationTimeText(Math.abs(moment(v.request_time).diff(moment())), false)}<br />
                  {/* {util.getDurationTimeText(moment(v.request_time).startOf().fromNow()} */}
                </td>
                <td>{v.line_name}</td>
                <td>{v.machine_name}</td>
              </tr>
              <tr>
                <td colSpan={3}>
                  {v.request_cause}
                </td>
              </tr>
            </tbody>
          </Table>
        </Row >
      );
    });


    return (
      // <ContextMenuTrigger id="some_unique_identifier">
      //   <ContextMenu id="some_unique_identifier">
      //     <MenuItem data={{ foo: 'bar' }} onClick={this.handleClick}>
      //       ContextMenu Item 1
      //   </MenuItem>
      //     <MenuItem data={{ foo: 'bar' }} onClick={this.handleClick}>
      //       ContextMenu Item 2
      //   </MenuItem>
      //     <MenuItem divider />
      //     <MenuItem data={{ foo: 'bar' }} onClick={this.handleClick}>
      //       ContextMenu Item 3
      //   </MenuItem>
      //   </ContextMenu>

      <Container fluid>
        {this.props.title && <div style={{ textAlign: 'center', fontWeight: 'bold' }}>{this.props.title}</div>}
        <Row className="db-header" >
          <Col md={2}>
            Status
            </Col>
          <Col>
            Line/Machine/Cause
            </Col>
        </Row >
        {jobList}
      </Container >
      // </ContextMenuTrigger>

    );
  }
}
